import express, { Request, Response } from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI } from "@google/genai";

const app = express();
const PORT = 3000;

app.use(express.json());

// Lazy-loaded GenAI Client to prevent crash when GEMINI_API_KEY is not defined upon immediate server start
let genAI: GoogleGenAI | null = null;
function getGenAI(): GoogleGenAI {
  if (!genAI) {
    const apiKey = process.env.GEMINI_API_KEY;
    if (!apiKey) {
      throw new Error("GEMINI_API_KEY is not defined in environment variables. Please configure it in your Secrets/Settings panel.");
    }
    genAI = new GoogleGenAI({
      apiKey: apiKey,
      httpOptions: {
        headers: {
          "User-Agent": "aistudio-build",
        },
      },
    });
  }
  return genAI;
}

// REST API endpoint to generate custom cheatsheet via Gemini
app.post("/api/generate", async (req: Request, res: Response): Promise<void> => {
  try {
    const { toolName, customPrompt } = req.body;
    if (!toolName) {
      res.status(400).json({ error: "El nombre de la herramienta es obligatorio." });
      return;
    }

    const ai = getGenAI();
    const systemInstructions = `Eres un pentester senior especializado en crear referencias técnicas de alta calidad. Tu función es generar cheatsheets interactivas para herramientas de hacking y ciberseguridad, organizadas por casos de uso reales, no por flags alfabéticos.

PRINCIPIO FUNDAMENTAL:
Las cheatsheets se organizan por "¿qué quiero conseguir?", no por "¿qué flags existen?". Un pentester no busca flags, busca resolver una situación concreta.

Debes generar entre 6 y 10 casos de uso siguiendo esta estructura exacta (respeta rigurosamente los delimitadores y los nombres de campos):

===CASO===
TITULO: [Qué se consigue con este comando — acción concreta]
CATEGORIA: [Reconocimiento | Web | Passwords | Post-explotación | Evasión]
DIFICULTAD: [básico | intermedio | avanzado]
FRECUENCIA: [siempre | común | ocasional]

COMANDO:
[comando exacto con <parametro> en angle brackets para los valores variables]

FLAGS:
[flag corto o largo] → [explicación concreta de qué hace y cuándo usarlo]
[flag corto o largo] → [explicación concreta de qué hace y cuándo usarlo]
[añade tantos flags como aparezcan en el comando]

EJEMPLO:
[mismo comando con valores reales y concretos — nunca placeholders en el ejemplo, usa IPs de rangos RFC 1918 reales, dominios de práctica como target.htb, wordlists reales como /usr/share/wordlists/rockyou.txt]

TIP: [consejo práctico, gotcha, combinación con otra herramienta, o advertencia de opsec o rendimiento de la vida real]
===FIN===

Reglas de contenido:
1. Casos de uso reales encaminados a resolver un problema concreto en una auditoría de seguridad.
2. Ejemplos 100% reales. No uses dummy placeholders en "EJEMPLO".
3. Identifica correctamente la CATEGORIA (Reconocimiento, Web, Passwords, Post-explotación, Evasión).
4. El idioma de respuesta debe ser rigurosamente ESPAÑOL.`;

    const modelPrompt = `Genera la cheatsheet interactiva de grado profesional para la herramienta: "${toolName}".` + 
      (customPrompt ? ` Enfócate o añade este contexto adicional: ${customPrompt}.` : "") + 
      ` Asegúrate de proveer entre 6 y 10 casos de uso completos con el formato exacto de delimitadores ===CASO=== y ===FIN===. No pongas explicaciones introductorias ni de cierre; ve directo a los bloques de comandos.`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: modelPrompt,
      config: {
        systemInstruction: systemInstructions,
        temperature: 0.2, // low temperature for reliable formatting
      },
    });

    const text = response.text || "";
    res.json({ rawCheatsheet: text });
  } catch (error: any) {
    console.error("Error generating cheatsheet with Gemini:", error);
    res.status(500).json({ error: error.message || "Error al invocar la API de Gemini" });
  }
});

// Configure Vite or Static Assets
async function setupServer() {
  if (process.env.NODE_ENV !== "production") {
    console.log("Starting server in development mode with Vite middleware...");
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    console.log("Starting server in production mode...");
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server listening on http://0.0.0.0:${PORT}`);
  });
}

setupServer().catch((err) => {
  console.error("Failed to bootstrap server:", err);
});
